// Stop words that don't change market meaning
const STOP_WORDS = new Set([
  'will', 'the', 'a', 'an', 'of', 'in', 'on', 'by', 'to', 'and', 'or',
  'is', 'be', 'have', 'has', 'had', 'do', 'does', 'did', 'it', 'its',
  'this', 'that', 'for', 'with', 'at', 'from', 'as', 'into', 'through',
  'than', 'but', 'not', 'no', 'yes', 'if', 'then', 'so', 'up', 'down',
  'out', 'who', 'what', 'when', 'where', 'how', 'which',
  'their', 'there', 'they', 'we', 'our', 'us', 'he', 'she', 'his', 'her',
  'would', 'could', 'should', 'may', 'might', 'can', 'shall',
  'been', 'being', 'was', 'were', 'are', 'am',
  'more', 'most', 'some', 'any', 'all', 'each', 'every',
]);

export function tokenize(text: string): string[] {
  if (!text) return [];
  // Keep numbers, letters, $, %, and periods (for decimals)
  const cleaned = text.toLowerCase().replace(/[^a-z0-9$%.]/g, ' ');
  const tokens = cleaned.split(/\s+/).filter(t => t.length > 0);
  return tokens.filter(t => !STOP_WORDS.has(t));
}

// Extract all numbers (including those with $ signs) from tokens
function extractNumbers(tokens: string[]): string[] {
  const nums: string[] = [];
  for (const t of tokens) {
    // Extract numeric part (strip $ and %)
    const cleaned = t.replace(/[$%,]/g, '');
    if (/^\d+\.?\d*$/.test(cleaned)) {
      nums.push(cleaned);
    }
  }
  return nums;
}

export function computeMatchScore(tokensA: string[], tokensB: string[]): number {
  if (tokensA.length === 0 || tokensB.length === 0) return 0;

  const setA = new Set(tokensA);
  const setB = new Set(tokensB);

  let intersection = 0;
  for (const item of setA) {
    if (setB.has(item)) intersection++;
  }
  const union = new Set([...tokensA, ...tokensB]).size;
  if (union === 0) return 0;

  const jaccard = intersection / union;

  // Number matching is critical — different numbers = different market
  const numsA = extractNumbers(tokensA);
  const numsB = extractNumbers(tokensB);

  if (numsA.length > 0 && numsB.length > 0) {
    const sharedNums = numsA.filter(n => numsB.includes(n));
    const allNums = new Set([...numsA, ...numsB]);

    if (sharedNums.length === 0) {
      // No shared numbers = very likely different markets
      return Math.max(0, jaccard * 0.3); // Heavy penalty
    }

    // Bonus proportional to how many numbers match
    const numMatchRatio = sharedNums.length / allNums.size;
    return Math.min(1, jaccard + numMatchRatio * 0.2);
  }

  return jaccard;
}

export interface MarketMatch {
  polyIdx: number;
  kalshiIdx: number;
  score: number;
}

export function findBestMatches(
  polyTokens: string[][],
  kalshiTokens: string[][],
  threshold: number = 0.25
): MarketMatch[] {
  const candidates: MarketMatch[] = [];

  for (let pi = 0; pi < polyTokens.length; pi++) {
    for (let ki = 0; ki < kalshiTokens.length; ki++) {
      const score = computeMatchScore(polyTokens[pi], kalshiTokens[ki]);
      if (score >= threshold) {
        candidates.push({ polyIdx: pi, kalshiIdx: ki, score });
      }
    }
  }

  // Sort by score descending, then greedily assign 1:1
  candidates.sort((a, b) => b.score - a.score);
  const usedPoly = new Set<number>();
  const usedKalshi = new Set<number>();
  const matches: MarketMatch[] = [];

  for (const c of candidates) {
    if (usedPoly.has(c.polyIdx) || usedKalshi.has(c.kalshiIdx)) continue;
    matches.push(c);
    usedPoly.add(c.polyIdx);
    usedKalshi.add(c.kalshiIdx);
  }

  return matches;
}

