import { NormalizedMarket, ArbitrageOpportunity, Strategy } from '../types';
import { tokenize, findBestMatches } from './matching';

const GAMMA_BASE = 'https://gamma-api.polymarket.com';
const KALSHI_BASE = 'https://api.elections.kalshi.com/trade-api/v2';

async function proxyFetch(url: string): Promise<Response> {
  return fetch(`/api/proxy?url=${encodeURIComponent(url)}`);
}

export async function fetchPolymarketMarkets(): Promise<NormalizedMarket[]> {
  const markets: NormalizedMarket[] = [];

  // Fetch multiple pages for better coverage
  for (let offset = 0; offset < 300; offset += 100) {
    const url = `${GAMMA_BASE}/markets?closed=false&active=true&limit=100&offset=${offset}&order=volume24hr&ascending=false`;

    try {
      const res = await proxyFetch(url);
      if (!res.ok) continue;

      const data = await res.json();
      const list = Array.isArray(data) ? data : (data.markets || data.data || []);

      if (list.length === 0) break;

      for (const m of list) {
        try {
          if (m.closed || !m.active) continue;

          let outcomes: string[] = [];
          let prices: number[] = [];

          if (typeof m.outcomes === 'string') {
            outcomes = JSON.parse(m.outcomes);
          } else if (Array.isArray(m.outcomes)) {
            outcomes = m.outcomes;
          }

          if (typeof m.outcomePrices === 'string') {
            prices = JSON.parse(m.outcomePrices).map(Number);
          } else if (Array.isArray(m.outcomePrices)) {
            prices = m.outcomePrices.map(Number);
          }

          if (outcomes.length < 2 || prices.length < 2) continue;

          const yesPrice = prices[0] || 0;
          const noPrice = prices[1] || 0;

          // Skip markets with no meaningful price
          if (yesPrice <= 0.01 && noPrice <= 0.01) continue;
          // Skip markets that are basically resolved (99%+)
          if (yesPrice >= 0.99 || noPrice >= 0.99) continue;

          const title = m.question || m.groupItemTitle || m.title || '';
          if (!title) continue;

          const slug = m.slug || m.conditionId || '';
          const eventSlug = m.eventSlug || m.groupSlug || slug;

          markets.push({
            id: m.id || m.conditionId || `poly-${markets.length}`,
            platform: 'polymarket',
            title,
            yesPrice,
            noPrice,
            volume24h: parseFloat(m.volume24hr || m.volume || '0') || 0,
            url: eventSlug
              ? `https://polymarket.com/event/${eventSlug}`
              : `https://polymarket.com`,
          });
        } catch {
          // Skip malformed
        }
      }
    } catch {
      break;
    }
  }

  console.log(`[Poly] Parsed ${markets.length} markets`);
  return markets;
}

export async function fetchKalshiMarkets(): Promise<NormalizedMarket[]> {
  const markets: NormalizedMarket[] = [];
  let cursor = '';
  const maxPages = 4;

  for (let page = 0; page < maxPages; page++) {
    const params = new URLSearchParams({ status: 'open', limit: '200' });
    if (cursor) params.set('cursor', cursor);

    const url = `${KALSHI_BASE}/markets?${params.toString()}`;

    try {
      const res = await proxyFetch(url);
      if (!res.ok) {
        console.error(`[Kalshi] HTTP ${res.status}`);
        break;
      }

      const data = await res.json();
      const list = data.markets || [];

      if (!Array.isArray(list) || list.length === 0) break;

      // Debug: log first market on first page
      if (page === 0 && list.length > 0) {
        const s = list[0];
        console.log('[Kalshi] Sample:', JSON.stringify({
          ticker: s.ticker,
          title: s.title,
          status: s.status,
          yes_bid: s.yes_bid,
          yes_ask: s.yes_ask,
          no_bid: s.no_bid,
          no_ask: s.no_ask,
          yes_price: s.yes_price,
          no_price: s.no_price,
          yes_bid_dollars: s.yes_bid_dollars,
          yes_ask_dollars: s.yes_ask_dollars,
          no_bid_dollars: s.no_bid_dollars,
          no_ask_dollars: s.no_ask_dollars,
          last_price: s.last_price,
          last_price_dollars: s.last_price_dollars,
        }));
      }

      for (const m of list) {
        const status = (m.status || '').toLowerCase();
        if (status !== 'open' && status !== 'active') continue;

        // Try multiple price sources
        // 1. Dollar strings (0-1 range): yes_ask_dollars, yes_bid_dollars, last_price_dollars
        // 2. Cent integers (0-100 range): yes_price, yes_ask, yes_bid, last_price

        let yesPrice = 0;
        let noPrice = 0;

        // Try dollar string fields first (these are like "0.5600" = $0.56)
        const yesBidD = parseFloat(m.yes_bid_dollars || '0') || 0;
        const yesAskD = parseFloat(m.yes_ask_dollars || '0') || 0;
        const noBidD = parseFloat(m.no_bid_dollars || '0') || 0;
        const noAskD = parseFloat(m.no_ask_dollars || '0') || 0;
        const lastPriceD = parseFloat(m.last_price_dollars || '0') || 0;

        if (yesAskD > 0) {
          yesPrice = yesAskD;
        } else if (yesBidD > 0) {
          yesPrice = yesBidD;
        } else if (lastPriceD > 0) {
          yesPrice = lastPriceD;
        }

        if (noAskD > 0) {
          noPrice = noAskD;
        } else if (noBidD > 0) {
          noPrice = noBidD;
        } else if (yesPrice > 0) {
          noPrice = 1 - yesPrice;
        }

        // Fallback: try cent-integer fields (0-100)
        if (yesPrice === 0 && noPrice === 0) {
          const yesCent = Number(m.yes_price || m.yes_ask || m.yes_bid || 0);
          const noCent = Number(m.no_price || m.no_ask || m.no_bid || 0);
          const lastCent = Number(m.last_price || 0);

          if (yesCent > 0 && yesCent <= 100) {
            yesPrice = yesCent / 100;
          } else if (lastCent > 0 && lastCent <= 100) {
            yesPrice = lastCent / 100;
          }

          if (noCent > 0 && noCent <= 100) {
            noPrice = noCent / 100;
          } else if (yesPrice > 0) {
            noPrice = 1 - yesPrice;
          }
        }

        // Clamp
        yesPrice = Math.max(0.01, Math.min(0.99, yesPrice));
        noPrice = Math.max(0.01, Math.min(0.99, noPrice));

        if (yesPrice <= 0.02 && noPrice <= 0.02) continue;

        const title = m.title || m.subtitle || '';
        if (!title) continue;

        const ticker = m.ticker || '';
        const eventTicker = m.event_ticker || '';

        markets.push({
          id: ticker || `kalshi-${markets.length}`,
          platform: 'kalshi',
          title,
          yesPrice,
          noPrice,
          volume24h: parseFloat(m.volume_24h_fp || '0') || 0,
          url: `https://kalshi.com/markets/${eventTicker || ticker}`,
        });
      }

      cursor = data.cursor || '';
      if (!cursor) break;
    } catch (err: any) {
      console.error(`[Kalshi] Page ${page} error:`, err.message);
      break;
    }
  }

  console.log(`[Kalshi] Parsed ${markets.length} markets`);
  return markets;
}

function buildStrategy(
  polyAction: 'YES' | 'NO',
  kalshiAction: 'YES' | 'NO',
  poly: NormalizedMarket,
  kalshi: NormalizedMarket
): Strategy {
  const polyCost = polyAction === 'YES' ? poly.yesPrice : poly.noPrice;
  const kalshiCost = kalshiAction === 'YES' ? kalshi.yesPrice : kalshi.noPrice;
  const totalCost = polyCost + kalshiCost;
  const profit = 1 - totalCost;
  const profitPct = totalCost > 0 ? (profit / totalCost) * 100 : 0;

  return {
    label: `${polyAction}@Poly + ${kalshiAction}@Kalshi`,
    polyAction,
    kalshiAction,
    polyCost,
    kalshiCost,
    totalCost,
    profit,
    profitPct,
  };
}

export interface ScanResult {
  opportunities: ArbitrageOpportunity[];
  polyCount: number;
  kalshiCount: number;
  matchCount: number;
  error?: string;
  polySamples: string[];
  kalshiSamples: string[];
}

export async function scanArbitrage(): Promise<ScanResult> {
  let polyMarkets: NormalizedMarket[] = [];
  let kalshiMarkets: NormalizedMarket[] = [];
  const errors: string[] = [];

  const [polyResult, kalshiResult] = await Promise.allSettled([
    fetchPolymarketMarkets(),
    fetchKalshiMarkets(),
  ]);

  if (polyResult.status === 'fulfilled') {
    polyMarkets = polyResult.value;
  } else {
    errors.push(`Poly: ${polyResult.reason?.message || 'Failed'}`);
  }

  if (kalshiResult.status === 'fulfilled') {
    kalshiMarkets = kalshiResult.value;
  } else {
    errors.push(`Kalshi: ${kalshiResult.reason?.message || 'Failed'}`);
  }

  const polySamples = polyMarkets.slice(0, 5).map(m => `${m.title} (Y:${(m.yesPrice*100).toFixed(0)}¢)`);
  const kalshiSamples = kalshiMarkets.slice(0, 5).map(m => `${m.title} (Y:${(m.yesPrice*100).toFixed(0)}¢)`);

  if (polyMarkets.length === 0 || kalshiMarkets.length === 0) {
    return {
      opportunities: [],
      polyCount: polyMarkets.length,
      kalshiCount: kalshiMarkets.length,
      matchCount: 0,
      error: errors.length > 0 ? errors.join('; ') : 
        `No markets from ${polyMarkets.length === 0 ? 'Polymarket' : 'Kalshi'}`,
      polySamples,
      kalshiSamples,
    };
  }

  // Tokenize
  const polyTokens = polyMarkets.map(m => tokenize(m.title));
  const kalshiTokens = kalshiMarkets.map(m => tokenize(m.title));

  // Find matches  
  const matches = findBestMatches(polyTokens, kalshiTokens, 0.25);

  console.log(`[Match] ${matches.length} matches from ${polyMarkets.length}×${kalshiMarkets.length}`);

  const opportunities: ArbitrageOpportunity[] = [];

  for (const match of matches) {
    const poly = polyMarkets[match.polyIdx];
    const kalshi = kalshiMarkets[match.kalshiIdx];

    // Two possible strategies
    const stratA = buildStrategy('YES', 'NO', poly, kalshi);
    const stratB = buildStrategy('NO', 'YES', poly, kalshi);
    const bestStrategy = stratA.profit > stratB.profit ? stratA : stratB;

    const spread = Math.abs(poly.yesPrice - kalshi.yesPrice);

    opportunities.push({
      id: `${poly.id}-${kalshi.id}`,
      polyMarket: poly,
      kalshiMarket: kalshi,
      matchScore: match.score,
      bestStrategy,
      spread,
      hasArb: bestStrategy.profit > 0,
    });
  }

  // Sort: arbs first by profit, then by spread
  opportunities.sort((a, b) => {
    if (a.hasArb && !b.hasArb) return -1;
    if (!a.hasArb && b.hasArb) return 1;
    if (a.hasArb && b.hasArb) return b.bestStrategy.profitPct - a.bestStrategy.profitPct;
    return b.spread - a.spread;
  });

  return {
    opportunities,
    polyCount: polyMarkets.length,
    kalshiCount: kalshiMarkets.length,
    matchCount: matches.length,
    error: errors.length > 0 ? errors.join('; ') : undefined,
    polySamples,
    kalshiSamples,
  };
}

